### 📄 `knn_wrapper.cpp`
```cpp
#include "knn_wrapper.h"
#include <fstream>
#include <iostream>
#include <algorithm>
#include <numeric>
#include <chrono>

KNNWrapper::KNNWrapper(int device_id) : device_id_(device_id) {
    CUDA_CHECK(cudaSetDevice(device_id_));
    CUDA_CHECK(cudaStreamCreate(&stream_));
    CUDA_CHECK(cudaEventCreate(&start_event_));
    CUDA_CHECK(cudaEventCreate(&stop_event_));
}

KNNWrapper::~KNNWrapper() {
    freeDeviceMemory();
    CUDA_CHECK(cudaEventDestroy(start_event_));
    CUDA_CHECK(cudaEventDestroy(stop_event_));
    CUDA_CHECK(cudaStreamDestroy(stream_));
}

void KNNWrapper::loadDataset(const std::string& path) {
    std::ifstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot open dataset: " + path);

    file.read(reinterpret_cast<char*>(&num_points_), sizeof(num_points_));
    file.read(reinterpret_cast<char*>(&dim_), sizeof(dim_));
    h_dataset_.resize(num_points_ * dim_);
    file.read(reinterpret_cast<char*>(h_dataset_.data()), h_dataset_.size() * sizeof(float));
    file.close();

    allocateDeviceMemory();
    CUDA_CHECK(cudaMemcpyAsync(d_dataset_, h_dataset_.data(),
                               h_dataset_.size() * sizeof(float),
                               cudaMemcpyHostToDevice, stream_));
    CUDA_CHECK(cudaStreamSynchronize(stream_));
    logVerbose("Dataset loaded: " + std::to_string(num_points_) + " x " + std::to_string(dim_));
}

void KNNWrapper::allocateDeviceMemory() {
    freeDeviceMemory();
    CUDA_CHECK(cudaMalloc(&d_dataset_, num_points_ * dim_ * sizeof(float)));
    // CSR граф: row_offsets (N+1), indices (N*k), distances (N*k)
    size_t max_edges = num_points_ * graph_k_;
    CUDA_CHECK(cudaMalloc(&d_row_offsets_, (num_points_ + 1) * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_indices_, max_edges * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_distances_, max_edges * sizeof(float)));
}

void KNNWrapper::freeDeviceMemory() {
    if (d_dataset_) cudaFree(d_dataset_);
    if (d_row_offsets_) cudaFree(d_row_offsets_);
    if (d_indices_) cudaFree(d_indices_);
    if (d_distances_) cudaFree(d_distances_);
    d_dataset_ = d_row_offsets_ = d_indices_ = d_distances_ = nullptr;
}

void KNNWrapper::buildGraph(const GraphBuildParams& params) {
    graph_k_ = params.k;
    allocateDeviceMemory();
    buildGraphGPU(params.k);
    logVerbose("Graph built with k=" + std::to_string(graph_k_));
}

void KNNWrapper::refineGraph(const RefineParams& params) {
    refineGraphGPU(params);
    logVerbose("Graph refined");
}

void KNNWrapper::generateReferenceData() {
    generateReferenceDataGPU();
    logVerbose("Reference data generated");
}

EvaluationResult KNNWrapper::evaluateGraph() {
    if (h_ref_indices_.empty()) generateReferenceData();

    // Пример: оценка на первых 1000 точках
    int eval_size = std::min<size_t>(1000, num_points_);
    std::vector<float> queries(h_dataset_.begin(), h_dataset_.begin() + eval_size * dim_);
    auto res = query(queries, graph_k_, false, false);

    float recall = 0.0f;
    for (int i = 0; i < eval_size; ++i) {
        std::vector<int> pred(res.indices.begin() + i * graph_k_,
                              res.indices.begin() + (i + 1) * graph_k_);
        std::vector<int> ref(h_ref_indices_.begin() + i * graph_k_,
                             h_ref_indices_.begin() + (i + 1) * graph_k_);
        recall += computeRecallAtK(pred, ref, graph_k_);
    }
    recall /= eval_size;

    return {recall, 0.0, res.latency_ms, num_edges_};
}

QueryResult KNNWrapper::query(const std::vector<float>& queries, int k,
                              bool debug, bool verbose) {
    if (queries.size() % dim_ != 0) throw std::invalid_argument("Invalid query size");
    int num_queries = queries.size() / dim_;
    if (k > graph_k_) throw std::invalid_argument("k > graph_k_");

    float* d_queries = nullptr;
    int* d_indices = nullptr;
    float* d_distances = nullptr;
    CUDA_CHECK(cudaMalloc(&d_queries, queries.size() * sizeof(float)));
    CUDA_CHECK(cudaMalloc(&d_indices, num_queries * k * sizeof(int)));
    CUDA_CHECK(cudaMalloc(&d_distances, num_queries * k * sizeof(float)));

    CUDA_CHECK(cudaMemcpyAsync(d_queries, queries.data(), queries.size() * sizeof(float),
                               cudaMemcpyHostToDevice, stream_));

    CUDA_CHECK(cudaEventRecord(start_event_, stream_));
    queryGPU(d_queries, num_queries, k, d_indices, d_distances);
    CUDA_CHECK(cudaEventRecord(stop_event_, stream_));
    CUDA_CHECK(cudaStreamSynchronize(stream_));

    float ms = 0;
    CUDA_CHECK(cudaEventElapsedTime(&ms, start_event_, stop_event_));

    QueryResult result;
    result.indices.resize(num_queries * k);
    result.distances.resize(num_queries * k);
    result.latency_ms = ms;

    CUDA_CHECK(cudaMemcpy(result.indices.data(), d_indices,
                          num_queries * k * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(result.distances.data(), d_distances,
                          num_queries * k * sizeof(float), cudaMemcpyDeviceToHost));

    if (debug) {
        logDebug("Query debug: first 3 results");
        for (int i = 0; i < std::min(3, num_queries); ++i) {
            std::cout << "Q" << i << ": [";
            for (int j = 0; j < k; ++j) {
                std::cout << result.indices[i * k + j] << "(" << result.distances[i * k + j] << ") ";
            }
            std::cout << "]\n";
        }
    }
    if (verbose) {
        logVerbose("Query executed: " + std::to_string(num_queries) +
                   " queries, k=" + std::to_string(k) +
                   ", latency=" + std::to_string(ms) + " ms");
    }

    cudaFree(d_queries); cudaFree(d_indices); cudaFree(d_distances);
    return result;
}

void KNNWrapper::saveGraph(const std::string& path) const {
    std::ofstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot save graph: " + path);
    file.write(reinterpret_cast<const char*>(&num_points_), sizeof(num_points_));
    file.write(reinterpret_cast<const char*>(&graph_k_), sizeof(graph_k_));
    file.write(reinterpret_cast<const char*>(&num_edges_), sizeof(num_edges_));

    std::vector<int> h_offsets(num_points_ + 1);
    std::vector<int> h_indices(num_edges_);
    std::vector<float> h_dists(num_edges_);

    CUDA_CHECK(cudaMemcpy(h_offsets.data(), d_row_offsets_, (num_points_ + 1) * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(h_indices.data(), d_indices_, num_edges_ * sizeof(int), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(h_dists.data(), d_distances_, num_edges_ * sizeof(float), cudaMemcpyDeviceToHost));

    file.write(reinterpret_cast<const char*>(h_offsets.data()), h_offsets.size() * sizeof(int));
    file.write(reinterpret_cast<const char*>(h_indices.data()), h_indices.size() * sizeof(int));
    file.write(reinterpret_cast<const char*>(h_dists.data()), h_dists.size() * sizeof(float));
    file.close();
}

void KNNWrapper::loadGraph(const std::string& path) {
    std::ifstream file(path, std::ios::binary);
    if (!file) throw std::runtime_error("Cannot load graph: " + path);
    size_t n, k, edges;
    file.read(reinterpret_cast<char*>(&n), sizeof(n));
