    file.read(reinterpret_cast<char*>(h_offsets.data()), h_offsets.size() * sizeof(int));
    file.read(reinterpret_cast<char*>(h_indices.data()), h_indices.size() * sizeof(int));
    file.read(reinterpret_cast<char*>(h_dists.data()), h_dists.size() * sizeof(float));
    file.close();

    CUDA_CHECK(cudaMemcpy(d_row_offsets_, h_offsets.data(), h_offsets.size() * sizeof(int), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_indices_, h_indices.data(), h_indices.size() * sizeof(int), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_distances_, h_dists.data(), h_dists.size() * sizeof(float), cudaMemcpyHostToDevice));
}

