const fs = require('fs');
const path = require('path');

const ROOT_DIR = __dirname;
const SRC_DIR = path.join(ROOT_DIR, 'src');
const PUBLIC_DIR = path.join(ROOT_DIR, 'public');

// Вспомогательная функция: гарантированное создание директории
function ensureDir(dir) {
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
    console.log(`📁 Создана директория: ${path.relative(ROOT_DIR, dir)}`);
  }
}

// 1. Очистка и подготовка public/
function preparePublic() {
  if (fs.existsSync(PUBLIC_DIR)) {
    fs.rmSync(PUBLIC_DIR, { recursive: true, force: true });
    console.log('🧹 Очищен каталог public/');
  }
  ensureDir(PUBLIC_DIR);
  ['css', 'js', 'parsers', 'templates', 'assets'].forEach(sub => {
    ensureDir(path.join(PUBLIC_DIR, sub));
  });
}

// 2. Генерация файлов парсеров
function generateParsers() {
  const src = path.join(SRC_DIR, 'parsers');
  const out = path.join(PUBLIC_DIR, 'parsers');
  if (!fs.existsSync(src)) return console.warn('⚠️  src/parsers/ не найден, пропуск.');

  fs.readdirSync(src).forEach(file => {
    if (!file.endsWith('.json')) return;
    const raw = fs.readFileSync(path.join(src, file), 'utf8');
    // Пример трансформации: JSON → JS-модуль с валидацией
    const js = `// Автогенерированный парсер: ${file}\nmodule.exports = Object.freeze(${raw});\n`;
    fs.writeFileSync(path.join(out, file.replace('.json', '.js')), js);
  });
  console.log('🔧 Сгенерированы файлы парсеров');
}

// 3. Обработка шаблонов
function processTemplates() {
  const src = path.join(SRC_DIR, 'templates');
  const out = path.join(PUBLIC_DIR, 'templates');
  if (!fs.existsSync(src)) return console.warn('⚠️  src/templates/ не найден, пропуск.');

  const context = { TITLE: 'Web Project', VERSION: process.env.npm_package_version || '1.0.0' };

  fs.readdirSync(src).forEach(file => {
    if (!file.endsWith('.html')) return;
    let content = fs.readFileSync(path.join(src, file), 'utf8');
    // Простая подстановка {{KEY}} → value
    content = content.replace(/\{\{(\w+)\}\}/g, (_, key) => context[key] || `{{${key}}}`);
    fs.writeFileSync(path.join(out, file), content);
  });
  console.log('📄 Обработаны шаблоны');
}

// 4. Копирование ассетов
function copyAssets() {
  const src = path.join(SRC_DIR, 'assets');
  const out = path.join(PUBLIC_DIR, 'assets');
  if (!fs.existsSync(src)) return console.warn('⚠️  src/assets/ не найден, пропуск.');

  fs.cpSync(src, out, { recursive: true });
  console.log('📦 Скопированы ассеты');
}

// 5. Генерация финального index.html
function generateIndex() {
  const html = `<!DOCTYPE html>
<html lang="ru">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>Сборка завершена</title>
  <link rel="stylesheet" href="css/main.css">
</head>
<body>
  <main>
    <h1>✅ Проект успешно собран</h1>
    <p>Версия: ${process.env.npm_package_version || 'dev'}</p>
    <p>Дата сборки: ${new Date().toISOString()}</p>
  </main>
  <script src="js/app.js"></script>
</body>
</html>`;
  fs.writeFileSync(path.join(PUBLIC_DIR, 'index.html'), html);
  console.log('🌐 Сгенерирован index.html');
}

// 🚀 Главная функция сборки
function build() {
