### 📦 Полный код (`gol_simulator.cu`)

```cpp
#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <iostream>
#include <vector>
#include <string>
#include <cmath>
#include <cstdint>
#include <fstream>
#include <cassert>

// ========================
// 1. CUDA ЯДРО (Game of Life)
// ========================
#define BLOCK_X 32
#define BLOCK_Y 32

__global__ void gameOfLifeKernel(const uint8_t* __restrict__ d_in, 
                                 uint8_t* __restrict__ d_out, 
                                 int width, int height) {
    int tx = threadIdx.x;
    int ty = threadIdx.y;
    int bx = blockIdx.x;
    int by = blockIdx.y;

    // Глобальные координаты
    int x = bx * BLOCK_X + tx;
    int y = by * BLOCK_Y + ty;

    // Разделяемая память с halo-зоной (1 пиксель по краям)
    __shared__ uint8_t s_tile[BLOCK_Y + 2][BLOCK_X + 2];

    // Загрузка центрального элемента
    int x_wrap = (x + width) % width;
    int y_wrap = (y + height) % height;
    s_tile[ty + 1][tx + 1] = d_in[y_wrap * width + x_wrap];

    // Загрузка halo-зон (границ блока)
    if (tx == 0) {
        int x_left = (x - 1 + width) % width;
        s_tile[ty + 1][0] = d_in[y_wrap * width + x_left];
    }
    if (tx == BLOCK_X - 1) {
        int x_right = (x + 1) % width;
        s_tile[ty + 1][BLOCK_X + 1] = d_in[y_wrap * width + x_right];
    }
    if (ty == 0) {
        int y_top = (y - 1 + height) % height;
        s_tile[0][tx + 1] = d_in[y_top * width + x_wrap];
    }
    if (ty == BLOCK_Y - 1) {
        int y_bottom = (y + 1) % height;
        s_tile[BLOCK_Y + 1][tx + 1] = d_in[y_bottom * width + x_wrap];
    }
    // Углы
    if (tx == 0 && ty == 0) {
        int xl = (x - 1 + width) % width, yt = (y - 1 + height) % height;
        s_tile[0][0] = d_in[yt * width + xl];
    }
    if (tx == BLOCK_X - 1 && ty == 0) {
        int xr = (x + 1) % width, yt = (y - 1 + height) % height;
        s_tile[0][BLOCK_X + 1] = d_in[yt * width + xr];
    }
    if (tx == 0 && ty == BLOCK_Y - 1) {
        int xl = (x - 1 + width) % width, yb = (y + 1) % height;
        s_tile[BLOCK_Y + 1][0] = d_in[yb * width + xl];
    }
    if (tx == BLOCK_X - 1 && ty == BLOCK_Y - 1) {
        int xr = (x + 1) % width, yb = (y + 1) % height;
        s_tile[BLOCK_Y + 1][BLOCK_X + 1] = d_in[yb * width + xr];
    }

    __syncthreads();

    // Подсчёт соседей (3x3 вокруг центра)
    int neighbors = s_tile[ty][tx] + s_tile[ty][tx + 1] + s_tile[ty][tx + 2] +
                    s_tile[ty + 1][tx] + s_tile[ty + 1][tx + 2] +
                    s_tile[ty + 2][tx] + s_tile[ty + 2][tx + 1] + s_tile[ty + 2][tx + 2];

    // Правила Игры Жизни
    uint8_t current = s_tile[ty + 1][tx + 1];
    uint8_t next_state = 0;
    if (current == 1) {
        next_state = (neighbors == 2 || neighbors == 3) ? 1 : 0;
    } else {
        next_state = (neighbors == 3) ? 1 : 0;
    }

    // Запись результата (проверка границ для неполных блоков)
    if (x < width && y < height) {
        d_out[y * width + x] = next_state;
    }
}

// ========================
// 2. ВСПОМОГАТЕЛЬНЫЕ ФУНКЦИИ
// ========================

// Сохранение сетки в PPM (Grayscale)
void savePPM(const std::string& filename, const uint8_t* grid, int width, int height) {
    std::ofstream out(filename, std::ios::binary);
    out << "P5\n" << width << " " << height << "\n255\n";
    for (int i = 0; i < width * height; ++i) {
        uint8_t val = grid[i] ? 255 : 0;
        out.write(reinterpret_cast<char*>(&val), 1);
    }
    out.close();
    std::cout << "[INFO] Saved: " << filename << "\n";
}

// CPU-эталон для регрессионного тестирования
void cpuStep(const uint8_t* in, uint8_t* out, int width, int height) {
    for (int y = 0; y < height; ++y) {
        for (int x = 0; x < width; ++x) {
            int neighbors = 0;
            for (int dy = -1; dy <= 1; ++dy) {
                for (int dx = -1; dx <= 1; ++dx) {
                    if (dx == 0 && dy == 0) continue;
                    int nx = (x + dx + width) % width;
                    int ny = (y + dy + height) % height;
                    neighbors += in[ny * width + nx];
                }
            }
            int cur = in[y * width + x];
            out[y * width + x] = (cur == 1) ? ((neighbors == 2 || neighbors == 3) ? 1 : 0)
                                            : ((neighbors == 3) ? 1 : 0);
        }
    }
}

// ========================
// 3. КЛАСС СИМУЛЯТОРА (Multi-GPU Ready)
// ========================
class GoLSimulator {
public:
    GoLSimulator(int width, int height, int num_gpus) 
        : width(width), height(height), num_gpus(num_gpus) {
        assert(num_gpus > 0);
        grid_size = width * height;

        // Выделение хост-памяти
        h_grid[0] = new uint8_t[grid_size];
        h_grid[1] = new uint8_t[grid_size];
        h_ref     = new uint8_t[grid_size];

        // Инициализация GPU
        cudaGetDeviceCount(&device_count);
        if (num_gpus > device_count) {
            std::cerr << "[WARN] Requested " << num_gpus << " GPUs, but only " 
                      << device_count << " available. Using " << device_count << ".\n";
            num_gpus = device_count;
        }

        d_grid[0].resize(num_gpus);
        d_grid[1].resize(num_gpus);
        streams.resize(num_gpus);

        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaStreamCreate(&streams[i]);
            cudaMalloc(&d_grid[0][i], grid_size * sizeof(uint8_t));
            cudaMalloc(&d_grid[1][i], grid_size * sizeof(uint8_t));
        }
    }

    ~GoLSimulator() {
        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaFree(d_grid[0][i]);
            cudaFree(d_grid[1][i]);
            cudaStreamDestroy(streams[i]);
        }
        delete[] h_grid[0];
        delete[] h_grid[1];
        delete[] h_ref;
    }

    void initializeRandom() {
        for (int i = 0; i < grid_size; ++i) {
            h_grid[0][i] = (rand() % 4 == 0) ? 1 : 0;
        }
        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaMemcpyAsync(d_grid[0][i], h_grid[0], grid_size * sizeof(uint8_t), 
                            cudaMemcpyHostToDevice, streams[i]);
        }
        current_buf = 0;
    }

    void step() {
        dim3 block(BLOCK_X, BLOCK_Y);
        dim3 grid((width + BLOCK_X - 1) / BLOCK_X, (height + BLOCK_Y - 1) / BLOCK_Y);

        int next_buf = 1 - current_buf;

        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            gameOfLifeKernel<<<grid, block, 0, streams[i]>>>(
                d_grid[current_buf][i], d_grid[next_buf][i], width, height);
        }

        // Синхронизация всех потоков
        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaStreamSynchronize(streams[i]);
        }

        current_buf = next_buf;
    }

    // Регрессионный тест с сохранением изображения при ошибке
    bool runRegressionTest(int steps) {
        // Инициализация известным паттерном (Blinker 3x1)
        std::fill(h_grid[0], h_grid[0] + grid_size, 0);
        int cx = width / 2, cy = height / 2;
        h_grid[0][cy * width + cx - 1] = 1;
        h_grid[0][cy * width + cx]     = 1;
        h_grid[0][cy * width + cx + 1] = 1;

        // Копирование на GPU
        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaMemcpyAsync(d_grid[0][i], h_grid[0], grid_size * sizeof(uint8_t), 
                            cudaMemcpyHostToDevice, streams[i]);
        }
        current_buf = 0;

        // Запуск симуляции
        for (int s = 0; s < steps; ++s) step();

        // Копирование результата обратно
        uint8_t* h_result = new uint8_t[grid_size];
        for (int i = 0; i < num_gpus; ++i) {
            cudaSetDevice(i);
            cudaMemcpyAsync(h_result, d_grid[current_buf][i], grid_size * sizeof(uint8_t), 
                            cudaMemcpyDeviceToHost, streams[i]);
        }
        for (int i = 0; i < num_gpus; ++i) cudaStreamSynchronize(streams[i]);

        // CPU эталон
        std::copy(h_grid[0], h_grid[0] + grid_size, h_ref);
        for (int s = 0; s < steps; ++s) {
            std::copy(h_ref, h_ref + grid_size, h_grid[1]);
            cpuStep(h_grid[1], h_ref, width, height);
        }

        // Сравнение
        bool match = true;
        for (int i = 0; i < grid_size; ++i) {
            if (h_result[i] != h_ref[i]) {
                match = false;
                break;
            }
        }

        if (!match) {
            std::cerr << "[FAIL] Regression test failed at step " << steps << "\n";
            savePPM("gol_regression_fail.ppm", h_result, width, height);
        } else {
            std::cout << "[PASS] Regression test passed.\n";
        }

        delete[] h_result;
        return match;
    }

private:
    int width, height, grid_size, num_gpus, device_count;
    int current_buf = 0;
    uint8_t* h_grid[2];
    uint8_t* h_ref;
    std::vector<uint8_t*> d_grid[2];
    std::vector<cudaStream_t> streams;
};

// ========================
// 4. ТОЧКА ВХОДА
// ========================
int main() {
    const int WIDTH = 1024;
    const int HEIGHT = 1024;
    const int NUM_GPUS = 2; // Укажите количество доступных GPU
    const int STEPS = 100;

    std::cout << "Initializing GoL Simulator: " << WIDTH << "x" << HEIGHT 
              << " on " << NUM_GPUS << " GPU(s)...\n";

    GoLSimulator sim(WIDTH, HEIGHT, NUM_GPUS);
    sim.initializeRandom();

    // Запуск регрессионного теста
    sim.runRegressionTest(STEPS);

    // Пример производительностного запуска (без проверок)
    std::cout << "Running performance benchmark (" << STEPS << " steps)...\n";
    auto start = std::chrono::high_resolution_clock::now();
    for (int i = 0; i < STEPS; ++i) sim.step();
    auto end = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double> elapsed = end - start;
    std::cout << "Time: " << elapsed.count() << " s | " 
              << (STEPS / elapsed.count()) << " steps/sec\n";

    return 0;
}
